class Solution:
    def minimumLines(self, stockPrices):
        pts = sorted(stockPrices)
        n = len(pts)
        if n < 2:
            return 0
        lines = 1
        for i in range(2, n):
            x1, y1 = pts[i - 2]
            x2, y2 = pts[i - 1]
            x3, y3 = pts[i]
            if (y2 - y1) * (x3 - x2) != (y3 - y2) * (x2 - x1):
                lines += 1
        return lines

