var minimumLines = function(stockPrices) {
    const pts = stockPrices.slice().sort((a, b) => a[0] - b[0]);
    const n = pts.length;
    if (n < 2) return 0;
    let lines = 1;
    for (let i = 2; i < n; i++) {
        const [x1, y1] = pts[i - 2];
        const [x2, y2] = pts[i - 1];
        const [x3, y3] = pts[i];
        const lhs = BigInt(y2 - y1) * BigInt(x3 - x2);
        const rhs = BigInt(y3 - y2) * BigInt(x2 - x1);
        if (lhs !== rhs) lines++;
    }
    return lines;
};
